class RangeModule {
    private TreeSet<Interval> intervals;

    public RangeModule() {
        intervals = new TreeSet<>();
    }

    public void addRange(int left, int right) {
        Interval newInterval = new Interval(left, right);
        List<Interval> toRemove = new ArrayList<>();
        for (Interval interval : intervals.subSet(new Interval(left, left), new Interval(right, right))) {
            if (newInterval.contains(interval)) {
                toRemove.add(interval);
            } else {
                newInterval.merge(interval);
            }
        }
        for (Interval interval : toRemove) {
            intervals.remove(interval);
        }
        intervals.add(newInterval);
    }

    public boolean queryRange(int left, int right) {
        Interval floor = intervals.floor(new Interval(left, left));
        return floor != null && floor.right >= right;
    }

    public void removeRange(int left, int right) {
        List<Interval> toAdd = new ArrayList<>();
        List<Interval> toRemove = new ArrayList<>();
        for (Interval interval : intervals.subSet(new Interval(left, left), new Interval(right, right))) {
            toRemove.add(interval);
            if (interval.left < left) {
                toAdd.add(new Interval(interval.left, left));
            }
            if (interval.right > right) {
                toAdd.add(new Interval(right, interval.right));
            }
        }
        for (Interval interval : toRemove) {
            intervals.remove(interval);
        }
        for (Interval interval : toAdd) {
            intervals.add(interval);
        }
    }

    private static class Interval implements Comparable<Interval> {
        int left;
        int right;

        Interval(int left, int right) {
            this.left = left;
            this.right = right;
        }

        boolean contains(Interval other) {
            return this.left <= other.left && this.right >= other.right;
        }

        void merge(Interval other) {
            this.left = Math.min(this.left, other.left);
            this.right = Math.max(this.right, other.right);
        }

        @Override
        public int compareTo(Interval other) {
            if (this.left != other.left) {
                return Integer.compare(this.left, other.left);
            }
            return Integer.compare(this.right, other.right);
        }
    }
}
